mapper.select:
SELECT @rownum := @rownum + 1 AS `rank`, user_id, username, nickname, avatar_url, dimension_value, decimal_value, extra_data, create_time FROM ( SELECT user_id, MAX(username) AS username, MAX(nickname) AS nickname, MAX(avatar_url) AS avatar_url, MAX(dimension_value) AS dimension_value, MAX(decimal_value) AS decimal_value, MAX(extra_data) AS extra_data, MAX(create_time) AS create_time FROM t_leaderboard_data WHERE game_id = #{gameId} AND dimension_code = #{dimensionCode} AND deleted = 0
AND rank_type = #{rankType}
AND rank_date = #{rankDate}
AND rank_month = #{rankMonth}
AND rank_year = #{rankYear}
GROUP BY user_id ORDER BY dimension_value DESC LIMIT #{limit} ) AS ranked_data, (SELECT @rownum := 0) AS r

SELECT 
    (
        SELECT 
            CASE 
                WHEN userMaxValue IS NULL THEN NULL
                ELSE (
                    SELECT COUNT(*) + 1
                    FROM t_leaderboard_data ld1
                    WHERE ld1.game_id = #{gameId}
                      AND ld1.dimension_code = #{dimensionCode}
                      AND ld1.deleted = 0
                      AND ld1.dimension_value > userMaxValue
                )
            END
        FROM (
            SELECT MAX(dimension_value) AS userMaxValue
            FROM t_leaderboard_data
            WHERE user_id = #{userId}
              AND game_id = #{gameId}
              AND dimension_code = #{dimensionCode}
              AND deleted = 0
        ) AS user_best
    ) AS userRank,
    (
        SELECT MAX(dimension_value)
        FROM t_leaderboard_data
        WHERE user_id = #{userId}
          AND game_id = #{gameId}
          AND dimension_code = #{dimensionCode}
          AND deleted = 0
    ) AS userValue,
    (
        SELECT COUNT(DISTINCT user_id)
        FROM t_leaderboard_data
        WHERE game_id = #{gameId}
          AND dimension_code = #{dimensionCode}
          AND deleted = 0
    ) AS totalCount
